package com.blissless.tensei.extensionsimport android.content.ClipDataimport android.content.ClipboardManagerimport android.content.Contextimport android.widget.Toastimport androidx.compose.foundation.layout.*import androidx.compose.foundation.lazy.LazyColumnimport androidx.compose.material.icons.Iconsimport androidx.compose.material.icons.automirrored.filled.ArrowBackimport androidx.compose.material.icons.filled.Closeimport androidx.compose.material.icons.filled.ContentCopyimport androidx.compose.material.icons.filled.Downloadimport androidx.compose.material.icons.filled.Searchimport androidx.compose.material3.*import androidx.compose.runtime.*import androidx.compose.ui.Alignmentimport androidx.compose.ui.Modifierimport androidx.compose.ui.text.font.FontWeightimport androidx.compose.ui.text.style.TextOverflowimport androidx.compose.ui.unit.dp@OptIn(ExperimentalMaterial3Api::class)@Composablefun ExtensionBrowserScreen(    repoState: RepoState,    installedPackages: Set<String>,    onInstall: (RepoExtension) -> Unit,    onBack: () -> Unit,    onRemoveRepo: (String) -> Unit = {}) {    var searchQuery by remember { mutableStateOf("") }    var showRemoveDialog by remember { mutableStateOf(false) }    if (showRemoveDialog) {        AlertDialog(            onDismissRequest = { showRemoveDialog = false },            title = { Text("Remove repo?") },            text = {                Text("This will remove ${repoState.repo?.name ?: repoState.url} from your repos.")            },            confirmButton = {                TextButton(                    onClick = {                        showRemoveDialog = false                        onRemoveRepo(repoState.url)                        onBack()                    }                ) {                    Text("Remove", color = MaterialTheme.colorScheme.error)                }            },            dismissButton = {                TextButton(onClick = { showRemoveDialog = false }) {                    Text("Cancel")                }            }        )    }    val extensions = repoState.repo?.extensions ?: emptyList()    val filteredExtensions = if (searchQuery.isBlank()) {        extensions    } else {        extensions.filter {            it.name.contains(searchQuery, ignoreCase = true) ||            it.packageName.contains(searchQuery, ignoreCase = true)        }    }    Scaffold(        topBar = {            TopAppBar(                title = {                    Column {                        Text(                            text = repoState.repo?.name ?: repoState.url,                            style = MaterialTheme.typography.titleMedium,                            maxLines = 1,                            overflow = TextOverflow.Ellipsis                        )                        val description = repoState.repo?.description                        if (!description.isNullOrBlank()) {                            Text(                                text = description,                                style = MaterialTheme.typography.bodySmall,                                color = MaterialTheme.colorScheme.onSurfaceVariant,                                maxLines = 1,                                overflow = TextOverflow.Ellipsis                            )                        }                    }                },                navigationIcon = {                    IconButton(onClick = onBack) {                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back")                    }                },                actions = {                    val ctx = androidx.compose.ui.platform.LocalContext.current                    IconButton(                        onClick = {                            val clipboard = ctx.getSystemService(Context.CLIPBOARD_SERVICE) as ClipboardManager                            clipboard.setPrimaryClip(ClipData.newPlainText("Repo URL", repoState.url))                            Toast.makeText(ctx, "URL copied", Toast.LENGTH_SHORT).show()                        }                    ) {                        Icon(Icons.Default.ContentCopy, contentDescription = "Copy URL")                    }                    IconButton(onClick = { showRemoveDialog = true }) {                        Icon(Icons.Default.Close, contentDescription = "Remove repo")                    }                },                colors = TopAppBarDefaults.topAppBarColors(                    containerColor = MaterialTheme.colorScheme.surface                )            )        }    ) { padding ->        Column(            modifier = Modifier.fillMaxSize().padding(padding)        ) {            OutlinedTextField(                value = searchQuery,                onValueChange = { searchQuery = it },                label = { Text("Search") },                placeholder = { Text("Filter extensions...") },                modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp, vertical = 8.dp),                singleLine = true,                shape = androidx.compose.foundation.shape.RoundedCornerShape(12.dp),                colors = OutlinedTextFieldDefaults.colors(                    unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.25f),                    focusedBorderColor = MaterialTheme.colorScheme.primary.copy(alpha = 0.6f),                    unfocusedContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f),                    focusedContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f),                ),                leadingIcon = {                    Icon(Icons.Default.Search, contentDescription = "Search")                },                trailingIcon = {                    if (searchQuery.isNotEmpty()) {                        IconButton(onClick = { searchQuery = "" }) {                            Icon(Icons.Default.Close, contentDescription = "Clear")                        }                    }                }            )            if (repoState.isLoading) {                LinearProgressIndicator(modifier = Modifier.fillMaxWidth())            }            repoState.error?.let { error ->                Text(                    text = error,                    color = MaterialTheme.colorScheme.error,                    style = MaterialTheme.typography.bodySmall,                    modifier = Modifier.padding(horizontal = 16.dp, vertical = 8.dp)                )            }            if (filteredExtensions.isEmpty() && !repoState.isLoading) {                Box(                    modifier = Modifier.fillMaxSize(),                    contentAlignment = Alignment.Center                ) {                    Text(                        text = if (searchQuery.isNotBlank()) "No matching extensions"                               else "No extensions available",                        style = MaterialTheme.typography.bodyLarge,                        color = MaterialTheme.colorScheme.onSurfaceVariant                    )                }            } else {                LazyColumn(                    modifier = Modifier.fillMaxSize(),                    contentPadding = PaddingValues(horizontal = 16.dp, vertical = 8.dp),                    verticalArrangement = Arrangement.spacedBy(4.dp)                ) {                    items(filteredExtensions.size) { index ->                        val ext = filteredExtensions[index]                        ExtensionBrowserItem(                            repoExtension = ext,                            isInstalled = ext.packageName in installedPackages,                            onInstall = { onInstall(ext) }                        )                        if (index < filteredExtensions.lastIndex) {                            HorizontalDivider()                        }                    }                }            }        }    }}@Composableprivate fun ExtensionBrowserItem(    repoExtension: RepoExtension,    isInstalled: Boolean,    onInstall: () -> Unit) {    Row(        modifier = Modifier            .fillMaxWidth()            .padding(vertical = 8.dp),        verticalAlignment = Alignment.CenterVertically,        horizontalArrangement = Arrangement.spacedBy(12.dp)    ) {        Column(modifier = Modifier.weight(1f)) {            Text(                text = repoExtension.name,                style = MaterialTheme.typography.bodyLarge,                fontWeight = FontWeight.Medium,                maxLines = 1,                overflow = TextOverflow.Ellipsis            )            Row(                horizontalArrangement = Arrangement.spacedBy(8.dp),                verticalAlignment = Alignment.CenterVertically            ) {                Text(                    text = repoExtension.lang.uppercase(),                    style = MaterialTheme.typography.labelSmall,                    color = MaterialTheme.colorScheme.primary                )                if (repoExtension.version.isNotBlank()) {                    Text(                        text = "v${repoExtension.version}",                        style = MaterialTheme.typography.labelSmall,                        color = MaterialTheme.colorScheme.onSurfaceVariant                    )                }                if (repoExtension.nsfw) {                    Surface(                        color = MaterialTheme.colorScheme.errorContainer,                        shape = MaterialTheme.shapes.small                    ) {                        Text(                            text = "NSFW",                            style = MaterialTheme.typography.labelSmall,                            color = MaterialTheme.colorScheme.onErrorContainer,                            modifier = Modifier.padding(horizontal = 4.dp, vertical = 1.dp)                        )                    }                }                if (repoExtension.sources.isNotEmpty()) {                    Text(                        text = "${repoExtension.sources.size} source(s)",                        style = MaterialTheme.typography.labelSmall,                        color = MaterialTheme.colorScheme.onSurfaceVariant                    )                }            }        }        if (isInstalled) {            Text(                text = "Installed",                style = MaterialTheme.typography.labelMedium,                color = MaterialTheme.colorScheme.primary            )        } else {            FilledTonalButton(onClick = onInstall) {                Icon(                    Icons.Default.Download,                    contentDescription = null,                    modifier = Modifier.size(18.dp)                )                Spacer(modifier = Modifier.width(6.dp))                Text("Install")            }        }    }}